/// An immutable, owned composition root for one-shot calls.
/// It borrows its adapters through a fresh `Ctx` per call, but does not
/// carry model mutations between calls; mutable inbounds need a stateful root.
pub struct Standalone<
    ProjectAdapter: Project,
    WorkspaceAdapter: Workspace,
    CheckpointAdapter: Checkpoint,
    CalculatorAdapter: theseus_calculator::CalculatorService,
    ToolchainAdapter: Toolchain,
> {
    pub model: theseus_modeling::Model,
    pub project: ProjectAdapter,
    pub workspace: WorkspaceAdapter,
    pub checkpoint: CheckpointAdapter,
    pub calculator: CalculatorAdapter,
    pub toolchain: ToolchainAdapter,
}

impl<
    ProjectAdapter: Project,
    WorkspaceAdapter: Workspace,
    CheckpointAdapter: Checkpoint,
    CalculatorAdapter: theseus_calculator::CalculatorService,
    ToolchainAdapter: Toolchain,
> Standalone<
    ProjectAdapter,
    WorkspaceAdapter,
    CheckpointAdapter,
    CalculatorAdapter,
    ToolchainAdapter,
> {
    /// The borrowed composition root one call runs over.
    fn ctx(&self) -> Ctx<'_> {
        Ctx {
            model: &self.model,
            project: &self.project,
            workspace: &self.workspace,
            checkpoint: &self.checkpoint,
            calculator: &self.calculator,
            toolchain: &self.toolchain,
        }
    }
}

