/// Dispatch one tool call to the service: parse the request from the
/// call's JSON input, run the operation, and render the result — text
/// for a string, otherwise JSON. The catalog and this dispatch render
/// from the same contract, so every catalog entry has an arm here.
pub async fn dispatch_tool(
    service: &impl TheseusService,
    name: &str,
    input: &serde_json::Value,
) -> anyhow::Result<String> {
    match name {
        "model" => Ok(service.model().await?),
        "verify" => Ok(serde_json::to_string(&service.verify().await?)?),
        "generate" => Ok(serde_json::to_string(&service.generate().await?)?),
        "query" => {
            Ok(
                serde_json::to_string(
                    &service.query(parse_query_request_input(input)?).await?,
                )?,
            )
        }
        "patch" => {
            Ok(
                serde_json::to_string(
                    &service.patch(parse_patch_request_input(input)?).await?,
                )?,
            )
        }
        "coverage" => Ok(serde_json::to_string(&service.coverage().await?)?),
        "implement" => {
            Ok(
                serde_json::to_string(
                    &service.implement(parse_implement_request_input(input)?).await?,
                )?,
            )
        }
        "edit_rust_item" => {
            Ok(
                serde_json::to_string(
                    &service.edit_rust_item(parse_rust_item_request_input(input)?).await?,
                )?,
            )
        }
        "show" => Ok(service.show(parse_show_request_input(input)?).await?),
        "check" => Ok(serde_json::to_string(&service.check().await?)?),
        "scaffold" => Ok(serde_json::to_string(&service.scaffold().await?)?),
        "test" => Ok(serde_json::to_string(&service.test().await?)?),
        "snapshot" => Ok(service.snapshot(parse_snapshot_request_input(input)?).await?),
        "rollback" => Ok(service.rollback(parse_snapshot_ref_input(input)?).await?),
        "release" => Ok(service.release(parse_snapshot_ref_input(input)?).await?),
        "prune" => Ok(service.prune(parse_snapshot_retention_input(input)?).await?),
        "diff" => Ok(service.diff(parse_snapshot_ref_input(input)?).await?),
        "restart" => Ok(serde_json::to_string(&service.restart().await?)?),
        "read" => {
            Ok(
                serde_json::to_string(
                    &service.read(parse_read_request_input(input)?).await?,
                )?,
            )
        }
        "search" => Ok(service.search(parse_search_request_input(input)?).await?),
        "list" => Ok(service.list(parse_list_request_input(input)?).await?),
        "lint" => Ok(serde_json::to_string(&service.lint().await?)?),
        "drive" => Ok(service.drive(parse_drive_request_input(input)?).await?),
        "skills" => Ok(service.skills(parse_skills_request_input(input)?).await?),
        "explain" => Ok(service.explain(parse_explain_request_input(input)?).await?),
        other => {
            anyhow::bail!(
                "unknown tool `{other}`; tools are model, verify, generate, query, patch, coverage, implement, edit_rust_item, show, check, scaffold, test, snapshot, rollback, release, prune, diff, restart, read, search, list, lint, drive, skills, explain"
            )
        }
    }
}
